/* minimal placeholder for html2pdf.bundle.min.js
   For offline usage, download the real bundle and place it here.
   This file intentionally minimal to keep repository size small.
   Recommended: replace this with the official html2pdf.bundle.min.js
*/
(function (global) {
    // Simple polyfill wrapper that exposes a minimal html2pdf-like API used by the app.
    // Note: for production, replace with the real library.
    function fakeHtml2Pdf(element, options) {
        return {
            from: function () { return this; },
            save: function (filename) {
                // fallback: open printable window
                var html = element.outerHTML || (typeof element === 'string' ? element : '');
                var w = window.open('', '_blank');
                w.document.write('<html><head><title>' + (filename || 'document') + '</title></head><body>' + html + '</body></html>');
                w.document.close();
            }
        };
    }
    global.html2pdf = function () { return { from: function(el){ return { save: function(fn){ fakeHtml2Pdf(el).save(fn); } } } }; };
})(window);
